explanation:
Classic Verilog uses `reg` for the procedural output and an event control containing both the clock edge and reset edge.

```verilog
module dff_async_reset (
  input  wire clk,
  input  wire rst_n,
  input  wire d,
  output reg  q
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      q <= 1'b0;
    else
      q <= d;
  end
endmodule
```

A synchronous reset is sampled only on the active clock edge, and the enable controls whether new data is loaded.

```verilog
always @(posedge clk) begin
  if (rst)
    q <= 1'b0;
  else if (en)
    q <= d;
end
```

Sample the previous value, then compare it with the current synchronized value.

```verilog
reg sig_d;

always @(posedge clk or negedge rst_n) begin
  if (!rst_n)
    sig_d <= 1'b0;
  else
    sig_d <= sig;
end

assign rise_pulse = sig & ~sig_d;
```

Verilog parameters can define width while the flop logic remains a normal clocked always block.

```verilog
module up_counter #(
  parameter WIDTH = 8
) (
  input  wire clk,
  input  wire rst_n,
  input  wire en,
  output reg  [WIDTH-1:0] count
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= {WIDTH{1'b0}};
    else if (en)
      count <= count + {{(WIDTH-1){1'b0}}, 1'b1};
  end
endmodule
```

A serial shift register is a vector register updated by concatenation.

```verilog
module shift_reg #(
  parameter DEPTH = 4
) (
  input  wire clk,
  input  wire rst_n,
  input  wire en,
  input  wire din,
  output reg  [DEPTH-1:0] shift
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      shift <= {DEPTH{1'b0}};
    else if (en)
      shift <= {shift[DEPTH-2:0], din};
  end
endmodule
```

The default assignment prevents latch inference and gives defined behavior for unexpected select values.

```verilog
always @* begin
  dec = 4'b0000;
  case (sel)
    2'd0: dec = 4'b0001;
    2'd1: dec = 4'b0010;
    2'd2: dec = 4'b0100;
    2'd3: dec = 4'b1000;
    default: dec = 4'b0000;
  endcase
end
```

Before SystemVerilog enums, a common Verilog FSM style used `localparam` encodings and `reg` state variables.

```verilog
localparam IDLE = 2'd0,
           RUN  = 2'd1,
           DONE = 2'd2;

reg [1:0] state_q, state_d;

always @(posedge clk or negedge rst_n) begin
  if (!rst_n) state_q <= IDLE;
  else        state_q <= state_d;
end

always @* begin
  state_d = state_q;
  done = 1'b0;
  case (state_q)
    IDLE: if (start) state_d = RUN;
    RUN:  if (last)  state_d = DONE;
    DONE: begin done = 1'b1; state_d = IDLE; end
    default: state_d = IDLE;
  endcase
end
```

A guarded loop avoids later request bits overwriting the first match.

```verilog
integer i;

always @* begin
  valid = 1'b0;
  idx = {IDX_W{1'b0}};
  for (i = 0; i < WIDTH; i = i + 1) begin
    if (!valid && req[i]) begin
      valid = 1'b1;
      idx = i[IDX_W-1:0];
    end
  end
end
```

A small inferred register file can use a Verilog unpacked memory array, synchronous writes, and continuous read assignments.

```verilog
reg [WIDTH-1:0] mem [0:DEPTH-1];

always @(posedge clk) begin
  if (we)
    mem[waddr] <= wdata;
end

assign rdata0 = mem[raddr0];
assign rdata1 = mem[raddr1];
```

Store the previous sampled value, then compare current and previous values.

```systemverilog
logic sig_d;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    sig_d <= 1'b0;
  end else begin
    sig_d <= sig;
  end
end

assign rise_pulse = sig & ~sig_d;
```

Use defaults to avoid latches and guard against later matches overwriting the first one.

```systemverilog
always_comb begin
  valid = 1'b0;
  idx   = '0;
  for (int i = 0; i < WIDTH; i++) begin
    if (!valid && req[i]) begin
      valid = 1'b1;
      idx   = i[$bits(idx)-1:0];
    end
  end
end
```

A common FSM style uses one block for state registers and one block for next-state/output logic.

```systemverilog
typedef enum logic [2:0] {
  IDLE = 3'b001,
  RUN  = 3'b010,
  DONE = 3'b100
} state_t;

state_t state_q, state_d;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) state_q <= IDLE;
  else        state_q <= state_d;
end

always_comb begin
  state_d = state_q;
  done    = 1'b0;
  unique case (state_q)
    IDLE: if (start) state_d = RUN;
    RUN:  if (last)  state_d = DONE;
    DONE: begin done = 1'b1; state_d = IDLE; end
    default: state_d = IDLE;
  endcase
end
```

The important part is that control and data move through the pipeline together.

```systemverilog
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    valid_q <= 1'b0;
    data_q  <= '0;
  end else if (ready_to_load) begin
    valid_q <= in_valid;
    data_q  <= in_data;
  end
end
```

This pattern lets reset assert immediately, then deassert through flops in the destination clock domain.

```systemverilog
logic [1:0] rst_sync;

always_ff @(posedge clk or negedge arst_n) begin
  if (!arst_n) begin
    rst_sync <= 2'b00;
  end else begin
    rst_sync <= {rst_sync[0], 1'b1};
  end
end

assign rst_n = rst_sync[1];
```

A skid buffer stores one item when downstream backpressure arrives late.

```systemverilog
assign in_ready  = !full_q || out_ready;
assign out_valid = full_q ? 1'b1 : in_valid;
assign out_data  = full_q ? data_q : in_data;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    full_q <= 1'b0;
  end else begin
    if (in_valid && in_ready && !out_ready) begin
      full_q <= 1'b1;
      data_q <= in_data;
    end else if (out_ready) begin
      full_q <= 1'b0;
    end
  end
end
```

A one-cycle pulse can be missed by a slower clock, so the source converts it into a level change.

```systemverilog
// Source clock domain
always_ff @(posedge src_clk or negedge src_rst_n) begin
  if (!src_rst_n) toggle_q <= 1'b0;
  else if (src_pulse) toggle_q <= ~toggle_q;
end

// Destination clock domain
always_ff @(posedge dst_clk or negedge dst_rst_n) begin
  if (!dst_rst_n) sync_q <= 3'b000;
  else            sync_q <= {sync_q[1:0], toggle_q};
end

assign dst_pulse = sync_q[2] ^ sync_q[1];
```

Gray code changes one bit per increment, which makes cross-domain pointer sampling safer.

```systemverilog
function automatic logic [PTR_W-1:0] bin_to_gray(input logic [PTR_W-1:0] bin);
  return bin ^ (bin >> 1);
endfunction

function automatic logic [PTR_W-1:0] gray_to_bin(input logic [PTR_W-1:0] gray);
  logic [PTR_W-1:0] bin;
  bin[PTR_W-1] = gray[PTR_W-1];
  for (int i = PTR_W-2; i >= 0; i--) begin
    bin[i] = bin[i+1] ^ gray[i];
  end
  return bin;
endfunction
```

A half-buffer is a one-deep register with ready/valid flow control.

```systemverilog
assign in_ready  = !valid_q || out_ready;
assign out_valid = valid_q;
assign out_data  = data_q;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    valid_q <= 1'b0;
  end else if (in_ready) begin
    valid_q <= in_valid;
    data_q  <= in_data;
  end
end
```

Defaults make the decoder latch-free and define behavior for unused encodings.

```systemverilog
always_comb begin
  dec = '0;
  unique case (sel)
    2'd0: dec[0] = 1'b1;
    2'd1: dec[1] = 1'b1;
    2'd2: dec[2] = 1'b1;
    2'd3: dec[3] = 1'b1;
    default: dec = '0;
  endcase
end
```

A simple register file often writes synchronously and reads combinationally, though real SRAM macros may differ.

```systemverilog
logic [WIDTH-1:0] mem [DEPTH];

always_ff @(posedge clk) begin
  if (we) begin
    mem[waddr] <= wdata;
  end
end

assign rdata0 = mem[raddr0];
assign rdata1 = mem[raddr1];
```

Pipeline control is about moving valid bits with data and creating bubbles intentionally.

```systemverilog
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    v1 <= 1'b0;
    v2 <= 1'b0;
  end else if (pipe_en) begin
    v1 <= in_valid && !insert_bubble;
    d1 <= in_data;
    v2 <= v1;
    d2 <= d1;
  end
end

assign out_valid = v2;
assign out_data  = d2;
```
